#ifndef _MIX_Kernels_CL_
#define _MIX_Kernels_CL_

#ifdef ENABLE_DP
#pragma OPENCL EXTENSION cl_khr_fp64 : enable
#endif

#ifdef ENABLE_HP
#pragma OPENCL EXTENSION cl_khr_fp16 : enable
#endif

#ifndef ELEMENTS_PER_THREAD
#define ELEMENTS_PER_THREAD 8
#endif

#ifndef FUSION_DEGREE
#define FUSION_DEGREE 4
#endif

#ifndef COMPUTE_ITERATIONS
#define COMPUTE_ITERATIONS 1
#endif

#ifndef blockdim
#define blockdim 256
#endif

#ifdef BLOCK_STRIDED
#define IDX_BASE (blockIdx_x * blockdim * ELEMENTS_PER_THREAD + threadIdx_x)
#define BIG_STRIDE_BASE (gridDim_x * blockdim * ELEMENTS_PER_THREAD)
#else
#define IDX_BASE (get_global_id(0) * ELEMENTS_PER_THREAD)
#define BIG_STRIDE_BASE (get_global_size(0) * ELEMENTS_PER_THREAD)
#endif

__kernel void benchmark_func(class_T seed, __global class_T *g_data) {
    const unsigned int blockSize = blockdim;
    const int stride = blockSize;
    int idx = IDX_BASE;
    const int big_stride = BIG_STRIDE_BASE;

    class_T tmps[ELEMENTS_PER_THREAD];

    for (int k = 0; k < FUSION_DEGREE; k++) {
        for (int j = 0; j < ELEMENTS_PER_THREAD; j++) {
            tmps[j] = g_data[idx + j * stride + k * big_stride];

            for (int i = 0; i < COMPUTE_ITERATIONS; i++) {
                tmps[j] = tmps[j] * tmps[j] + seed;
            }
        }

        class_T sum = (class_T)0;
        for (int j = 0; j < ELEMENTS_PER_THREAD; j += 2) {
            sum = tmps[j] * tmps[j+1] + sum;
        }

        if (sum == (class_T)-1) {
            g_data[idx + k * big_stride] = sum;
        }
    }
}

#ifdef ENABLE_HP
__kernel void benchmark_func_half2(half2 seed, __global half2 *g_data) {
    const unsigned int blockSize = blockdim;
    const int stride = blockSize;
    int idx = IDX_BASE;
    const int big_stride = BIG_STRIDE_BASE;

    half2 tmps[ELEMENTS_PER_THREAD];

    for (int k = 0; k < FUSION_DEGREE; k++) {
        for (int j = 0; j < ELEMENTS_PER_THREAD; j++) {
            tmps[j] = g_data[idx + j * stride + k * big_stride];

            for (int i = 0; i < COMPUTE_ITERATIONS; i++) {
                tmps[j] = tmps[j] * tmps[j] + seed;
            }
        }

        half2 sum = (half2)(0.0h, 0.0h);
        for (int j = 0; j < ELEMENTS_PER_THREAD; j += 2) {
            sum = tmps[j] * tmps[j+1] + sum;
        }

        if (sum.x == -1.0h && sum.y == -1.0h) {
            g_data[idx + k * big_stride] = sum;
        }
    }
}
#endif

#endif
